const email = $input.item.json;
const subject = (email.subject || '').toLowerCase();
const from = (email.from || '').toLowerCase();
const body = (email.text || email.snippet || '').toLowerCase();

let emailType = 'unknown';
let priority = 'low';

// Detect rejection emails
const rejectionKeywords = ['unfortunately', 'decided to move forward with other', 'not moving forward', 'we will not', 'position has been filled', 'other candidates', 'thank you for your interest'];
const interviewKeywords = ['interview', 'schedule', 'availability', 'call', 'meeting', 'speak with'];
const offerKeywords = ['offer', 'congratulations', 'pleased to offer', 'compensation', 'start date'];
const followupKeywords = ['following up', 'checking in', 'status update', 'update on'];

if (offerKeywords.some(function(k) { return subject.includes(k) || body.includes(k); })) {
  emailType = 'offer';
  priority = 'critical';
} else if (interviewKeywords.some(function(k) { return subject.includes(k) || body.includes(k); })) {
  emailType = 'interview_invite';
  priority = 'high';
} else if (rejectionKeywords.some(function(k) { return body.includes(k); })) {
  emailType = 'rejection';
  priority = 'medium';
} else if (followupKeywords.some(function(k) { return subject.includes(k) || body.includes(k); })) {
  emailType = 'follow_up_response';
  priority = 'high';
}

return [{
  json: {
    email_id: email.id || '',
    subject: email.subject || '',
    from: email.from || '',
    received_at: email.date || new Date().toISOString(),
    email_type: emailType,
    priority: priority,
    snippet: (email.snippet || '').substring(0, 300)
  }
}];

const data = $input.item.json;
const { execSync } = require('child_process');
const dbPath = '/home/n8n/.n8n/job_search.db';

function escapeSql(s) {
  return String(s || '').replace(/'/g, "''");
}

function sqlExec(sql) {
  try {
    execSync('sqlite3 ' + dbPath, { input: sql, timeout: 10000 });
  } catch(e) {
    console.error('SQLite error:', e.message);
  }
}

sqlExec('CREATE TABLE IF NOT EXISTS email_tracking (id INTEGER PRIMARY KEY AUTOINCREMENT, email_id TEXT UNIQUE, subject TEXT, from_address TEXT, received_at TEXT, email_type TEXT, priority TEXT, snippet TEXT, processed_at TEXT DEFAULT CURRENT_TIMESTAMP);');

sqlExec('INSERT OR IGNORE INTO email_tracking (email_id, subject, from_address, received_at, email_type, priority, snippet) VALUES (\'' + escapeSql(data.email_id) + '\', \'' + escapeSql(data.subject) + '\', \'' + escapeSql(data.from) + '\', \'' + escapeSql(data.received_at) + '\', \'' + escapeSql(data.email_type) + '\', \'' + escapeSql(data.priority) + '\', \'' + escapeSql(data.snippet) + '\');');

console.log('Logged email: ' + data.email_type + ' from ' + data.from);
return [$input.item];
